import React, { useState } from 'react';
import { motion } from 'framer-motion';

const FluidSpineMenu = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isDarkMode, setIsDarkMode] = useState(false);
  
  const menuItems = [
    { id: 'home', label: 'Home' },
    { id: 'about', label: 'About' },
    { id: 'work', label: 'Work' },
    { id: 'content', label: 'Content' },
    { id: 'resources', label: 'Resources' }
  ];

  // Theme configuration
  // ============================================
  // PREVIOUS THEME (commented out for easy reversion)
  // ============================================
  // const theme = {
  //   light: {
  //     background: '#f9f9f9',
  //     text: '#111',
  //     textMuted: '#666',
  //     activeText: '#111',
  //     inactiveText: '#999',
  //     line: '#111',
  //     dot: '#111',
  //     divider: '#e0e0e0',
  //     socialIcon: '#666',
  //     headerButton: '#666'
  //   },
  //   dark: {
  //     background: '#1a1a1a',
  //     text: '#fff',
  //     textMuted: '#888',
  //     activeText: '#fff',
  //     inactiveText: '#666',
  //     line: '#fff',
  //     dot: '#fff',
  //     divider: '#333',
  //     socialIcon: '#888',
  //     headerButton: '#888'
  //   }
  // };
  // ============================================
  
  // NEW WARM EDITORIAL PALETTE
  const theme = {
    light: {
      // Core backgrounds - warmer cream/beige tones
      background: '#F3EEE7',        // Main canvas - warm cream
      backgroundSecondary: '#EBE6DE', // Sidebar, panels
      backgroundTertiary: '#E3DED5',  // Cards, subtle elevation
      // Typography - warm browns, not black
      text: '#2C2824',              // Main headings - dark warm brown
      textMuted: '#6B6560',         // Body copy
      activeText: '#2C2824',        // Active nav text
      inactiveText: '#A09A94',      // Inactive nav, captions
      // Lines & dividers
      line: '#2C2824',              // Active nav line
      dot: '#2C2824',               // Active nav dots
      divider: '#D5D0C9',           // Inactive dividers
      // Accent colors
      socialIcon: '#7A756E',        // Social icons
      headerButton: '#6B6560'       // Header buttons
    },
    dark: {
      // Core backgrounds - warm dark browns, cinematic
      background: '#1A1714',        // Main background - warm near-black
      backgroundSecondary: '#211E1A', // Sidebar
      backgroundTertiary: '#2A2622',  // Cards, panels
      // Typography - warm off-whites
      text: '#E3E0DB',              // Headings
      textMuted: '#A8A49E',         // Body
      activeText: '#E3E0DB',        // Active item
      inactiveText: '#6E6A64',      // Inactive nav
      // Lines & dividers
      line: '#E3E0DB',              // Active nav line
      dot: '#E3E0DB',               // Active nav dots
      divider: '#3D3935',           // Inactive dividers
      // Accent colors
      socialIcon: '#908C86',        // Social icons
      headerButton: '#A8A49E'       // Header buttons
    }
  };

  const currentTheme = isDarkMode ? theme.dark : theme.light;

  // Determine if line segment should be visible
  // Lines appear IMMEDIATELY ADJACENT to active item (both above AND below)
  const shouldShowLine = (afterIndex) => {
    if (afterIndex === activeIndex - 1) return true;
    if (afterIndex === activeIndex && activeIndex < menuItems.length - 1) return true;
    return false;
  };

  // Logo as base64
  const logoBase64 = "";

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      height: '100vh',
      backgroundColor: currentTheme.background,
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
      transition: 'background-color 0.3s ease'
    }}>
      {/* Header */}
      <header style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '24px 40px 16px 16px',
        backgroundColor: 'transparent'
      }}>
        {/* Logo */}
        <img 
          src={`data:image/png;base64,${logoBase64}`}
          alt="GT Strategies"
          style={{
            height: '37px',
            width: 'auto',
            marginLeft: '26px',
            objectFit: 'contain',
            filter: isDarkMode 
              ? 'brightness(0) saturate(100%) invert(89%)' // Matches #E3E0DB
              : 'brightness(0) saturate(100%) invert(15%)', // Matches #2C2824
            transition: 'filter 0.3s ease'
          }}
        />
        
        {/* Header Actions */}
        <div style={{
          display: 'flex',
          gap: '24px',
          alignItems: 'center'
        }}>
          {/* Dark Mode Toggle */}
          <motion.button
            onClick={() => setIsDarkMode(!isDarkMode)}
            style={{
              background: 'none',
              border: 'none',
              color: currentTheme.headerButton,
              fontSize: '14px',
              cursor: 'pointer',
              padding: '8px 12px',
              display: 'flex',
              alignItems: 'center',
              gap: '6px',
              opacity: 0.6,
              fontFamily: 'inherit'
            }}
            whileHover={{ opacity: 1 }}
            transition={{ duration: 0.2 }}
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              {isDarkMode ? (
                <>
                  <circle cx="12" cy="12" r="5"/>
                  <line x1="12" y1="1" x2="12" y2="3"/>
                  <line x1="12" y1="21" x2="12" y2="23"/>
                  <line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/>
                  <line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/>
                  <line x1="1" y1="12" x2="3" y2="12"/>
                  <line x1="21" y1="12" x2="23" y2="12"/>
                  <line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/>
                  <line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/>
                </>
              ) : (
                <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/>
              )}
            </svg>
          </motion.button>
          
          {/* Services Button */}
          <motion.button
            style={{
              background: 'none',
              border: 'none',
              color: currentTheme.headerButton,
              fontSize: '14px',
              cursor: 'pointer',
              padding: '8px 12px',
              opacity: 0.6,
              fontFamily: 'inherit'
            }}
            whileHover={{ opacity: 1 }}
            transition={{ duration: 0.2 }}
          >
            Services
          </motion.button>
          
          {/* Contact Button */}
          <motion.button
            style={{
              background: 'none',
              border: 'none',
              color: currentTheme.headerButton,
              fontSize: '14px',
              cursor: 'pointer',
              padding: '8px 12px',
              opacity: 0.6,
              fontFamily: 'inherit'
            }}
            whileHover={{ opacity: 1 }}
            transition={{ duration: 0.2 }}
          >
            Contact
          </motion.button>
        </div>
      </header>
      
      {/* Main Container */}
      <div style={{
        display: 'flex',
        flex: 1,
        overflow: 'hidden'
      }}>
        {/* Sidebar */}
        <aside style={{
          width: '100px',
          padding: '24px 20px 40px 37px',
          display: 'flex',
          flexDirection: 'column',
          marginLeft: '10px'
        }}>
          {/* Menu Container - flex: 1 fills the space, items stack inside */}
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            flex: 1,
            alignItems: 'center',
            minHeight: 0
          }}>
            {menuItems.map((item, index) => (
              <React.Fragment key={item.id}>
                {/* Menu Item - no flex-grow, just natural size */}
                <motion.div
                  onClick={() => setActiveIndex(index)}
                  style={{
                    cursor: 'pointer',
                    userSelect: 'none',
                    display: 'flex',
                    flexDirection: 'row',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flex: '0 0 auto',
                    paddingLeft: '20px',
                    paddingRight: '20px'
                  }}
                  whileHover={{ scale: 1.02 }}
                  transition={{ type: "spring", stiffness: 400, damping: 25 }}
                >
                  <motion.span
                    animate={{
                      color: index === activeIndex ? currentTheme.activeText : currentTheme.inactiveText,
                      fontWeight: index === activeIndex ? 500 : 400
                    }}
                    transition={{ duration: 0.3 }}
                    style={{
                      fontSize: '14px',
                      letterSpacing: '0.2px',
                      whiteSpace: 'nowrap',
                      paddingTop: '4px',
                      paddingBottom: '4px'
                    }}
                  >
                    {item.label}
                  </motion.span>
                </motion.div>

                {/* Line Segment - flexGrow animates to push items apart */}
                {index < menuItems.length - 1 && (
                  <motion.div
                    style={{
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      overflow: 'hidden'
                    }}
                    animate={{ 
                      flexGrow: shouldShowLine(index) ? 1 : 0,
                      opacity: shouldShowLine(index) ? 1 : 0,
                      marginTop: shouldShowLine(index) ? 10 : 0,
                      marginBottom: shouldShowLine(index) ? 10 : 0
                    }}
                    transition={{
                      flexGrow: {
                        type: "spring",
                        stiffness: 400,
                        damping: 35
                      },
                      opacity: {
                        duration: 0.2
                      },
                      marginTop: {
                        type: "spring",
                        stiffness: 400,
                        damping: 35
                      },
                      marginBottom: {
                        type: "spring",
                        stiffness: 400,
                        damping: 35
                      }
                    }}
                  >
                    {/* Top dot */}
                    <div style={{
                      width: '4px',
                      height: '4px',
                      backgroundColor: currentTheme.dot,
                      borderRadius: '50%'
                    }} />
                    
                    {/* Line */}
                    <div style={{
                      width: '1px',
                      flex: 1,
                      minHeight: '8px',
                      backgroundColor: currentTheme.line
                    }} />
                    
                    {/* Bottom dot */}
                    <div style={{
                      width: '4px',
                      height: '4px',
                      backgroundColor: currentTheme.dot,
                      borderRadius: '50%'
                    }} />
                  </motion.div>
                )}
              </React.Fragment>
            ))}
          </div>
          
          {/* Divider */}
          <div style={{
            width: '40px',
            height: '1px',
            backgroundColor: currentTheme.divider,
            marginTop: '20px',
            marginBottom: '28px',
            marginLeft: 'auto',
            marginRight: 'auto',
            transition: 'background-color 0.3s ease'
          }} />
          
          {/* Social Icons */}
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '24px',
            alignItems: 'center'
          }}>
            {/* LinkedIn */}
            <motion.a 
              href="https://linkedin.com" 
              target="_blank" 
              rel="noopener noreferrer"
              style={{
                color: currentTheme.socialIcon,
                cursor: 'pointer',
                textDecoration: 'none',
                display: 'flex',
                alignItems: 'center'
              }}
              whileHover={{ color: currentTheme.text }}
              transition={{ duration: 0.2 }}
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                <path d="M19 0h-14c-2.761 0-5 2.239-5 5v14c0 2.761 2.239 5 5 5h14c2.762 0 5-2.239 5-5v-14c0-2.761-2.238-5-5-5zm-11 19h-3v-11h3v11zm-1.5-12.268c-.966 0-1.75-.79-1.75-1.764s.784-1.764 1.75-1.764 1.75.79 1.75 1.764-.783 1.764-1.75 1.764zm13.5 12.268h-3v-5.604c0-3.368-4-3.113-4 0v5.604h-3v-11h3v1.765c1.396-2.586 7-2.777 7 2.476v6.759z"/>
              </svg>
            </motion.a>
            
            {/* YouTube */}
            <motion.a 
              href="https://youtube.com" 
              target="_blank" 
              rel="noopener noreferrer"
              style={{
                color: currentTheme.socialIcon,
                cursor: 'pointer',
                textDecoration: 'none',
                display: 'flex',
                alignItems: 'center'
              }}
              whileHover={{ color: currentTheme.text }}
              transition={{ duration: 0.2 }}
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                <path d="M19.615 3.184c-3.604-.246-11.631-.245-15.23 0-3.897.266-4.356 2.62-4.385 8.816.029 6.185.484 8.549 4.385 8.816 3.6.245 11.626.246 15.23 0 3.897-.266 4.356-2.62 4.385-8.816-.029-6.185-.484-8.549-4.385-8.816zm-10.615 12.816v-8l8 3.993-8 4.007z"/>
              </svg>
            </motion.a>
          </div>
        </aside>

        {/* Main Content */}
        <main style={{
          flex: 1,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '64px',
          overflow: 'auto'
        }}>
          <motion.div
            key={activeIndex}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ 
              type: "spring",
              stiffness: 400,
              damping: 35
            }}
            style={{
              maxWidth: '600px',
              textAlign: 'center'
            }}
          >
            <h1 style={{
              fontSize: '48px',
              fontWeight: '600',
              margin: '0 0 24px 0',
              color: currentTheme.text,
              transition: 'color 0.3s ease'
            }}>
              {menuItems[activeIndex].label}
            </h1>
            <p style={{
              fontSize: '16px',
              lineHeight: '1.6',
              color: currentTheme.textMuted,
              margin: 0,
              transition: 'color 0.3s ease'
            }}>
              Watch how the line segments expand only along the path to the active item, 
              while inactive items compress toward the edges. The active item grows and changes color.
            </p>
          </motion.div>
        </main>
      </div>
    </div>
  );
};

export default FluidSpineMenu;
